import{_ as a,o as l,c as i,a5 as r}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"教程 0039：三相 dq 电流环解耦","description":"","frontmatter":{"title":"教程 0039：三相 dq 电流环解耦","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0039-three-phase-current-loop-decoupling.html","status":"learning","visibility":"public","summary":"Imported from 0039-three-phase-current-loop-decoupling.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0039-three-phase-current-loop-decoupling.md","filePath":"content/power/lessons/0039-three-phase-current-loop-decoupling.md","lastUpdated":null}'),o={name:"content/power/lessons/0039-three-phase-current-loop-decoupling.md"};function t(d,e,n,h,p,c){return l(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="教程-0039-三相-dq-电流环解耦" tabindex="-1">教程 0039：三相 dq 电流环解耦 <a class="header-anchor" href="#教程-0039-三相-dq-电流环解耦" aria-label="Permalink to &quot;教程 0039：三相 dq 电流环解耦&quot;">​</a></h1><p>中文主讲。一个概念：dq 电流环解耦把旋转坐标系里的交叉耦合项前馈抵消，让 d 轴和 q 轴更像两个独立电流环。</p><p>目录</p><ul><li>它是什么</li><li>为什么 UPS 需要它</li><li>物理直觉</li><li>数学形式</li><li>一个仿真任务与仿真观察</li><li>固件落地</li><li>常见误解</li><li>验收标准、复盘问题、导师问题</li></ul><p>**保密边界：**本节只讲公开平均模型和教学 PI，不记录真实产品电感、带宽、限幅或电网适应策略。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>dq 电流环解耦（dq current loop decoupling）针对三相电感在旋转坐标系中的交叉项。d 轴变化会影响 q 轴，q 轴变化也会影响 d 轴，解耦前馈用于抵消 <code>omega * L</code> 相关项。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>Vienna PFC、PCS 并网跟随型控制和三相逆变器都依赖快速电流环。没有解耦时，id 阶跃可能让 iq 抖动，导致功率因数、无功控制或输出电压质量变差。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>dq 坐标系本身在旋转，电感电流像在转盘上行走的人。你向前走时会被转盘带出侧向速度，解耦项就是提前给一个反向补偿。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>vd_ref = PI(id_ref - id) - omega * L * iq + ed vq_ref = PI(iq_ref - iq) + omega * L * id + eq</p><p>其中 <code>ed/eq</code> 是电网或输出电压前馈。符号要和本项目的 Park 变换定义一致，不能只背公式。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>设置 id 从 0 阶跃到 10 A，iq_ref 保持 0。对比有无解耦：无解耦时 iq 出现明显暂态偏差，有解耦时 q 轴扰动更小。</p><p>产物</p><ul><li>一张 id/iq 阶跃响应对比图。</li><li>一段说明：解耦改善的是轴间串扰，不是替代 PI。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>代码通常在电流 PI 后加入 <code>wL = omega * L_filter</code>，再做电压限幅、反 Park、SVPWM。限幅后还要考虑抗积分饱和。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>**误解：**解耦项一定提高稳定性。 **纠正：**参数 L 或符号错会引入反向补偿。</li><li>**误解：**只要有解耦就不需要调 PI。 **纠正：**PI 仍决定基本动态和鲁棒性。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释 <code>omega * L * i</code> 的来源。</li><li>能说清 d 轴和 q 轴分别控制什么目标。</li><li>能指出解耦符号必须跟 Park 变换定义一致。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>为什么 50 Hz 下的解耦项和电感 L、负载电流有关？</li><li>限幅发生后，PI 积分器该如何处理？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>阅读真实代码时，电流环解耦、前馈和限幅的顺序通常如何确认？</li><li>我只讨论通用顺序，不记录项目参数。</li></ul><p>**下一步：**把 dq 电压参考转成三相 PWM，占空比由 SVPWM 生成。</p><p>源稿：<code>concepts/control/three-phase-current-loop-decoupling.md</code></p><p>上一节：教程 0038：三相 SRF-PLL 锁相下一节：教程 0040：两电平 SVPWM</p>',31)])])}const q=a(o,[["render",t]]);export{u as __pageData,q as default};
